foreach ($entry in $images.GetEnumerator()) {
  $dest = Join-Path $outDir $entry.Key
  try {
    Invoke-WebRequest -Uri $entry.Value -OutFile $dest -UseBasicParsing
    Write-Output "OK: $($entry.Key)"
  } catch {
    Write-Output "FAIL: $($entry.Key) - $_"
  }
}
